## 3. LiveKit Agent Implementation

### 3.1 Main Voice Agent

**File:** `agent/voice_agent.py`

```python
import asyncio
import os
from dataclasses import dataclass
from typing import Optional
from dotenv import load_dotenv

from livekit import rtc, agents
from livekit.plugins import deepgram, google, cartesia

from claude_bridge import ClaudeBridge

load_dotenv()

@dataclass
class AgentConfig:
    livekit_url: str
    livekit_api_key: str
    livekit_api_secret: str
    room_name: str
    deepgram_api_key: str
    google_api_key: str
    cartesia_api_key: str
    bridge_url: str
    voice_id: str = "79a125e8-cd45-4c81-8325-6caccb55b5a8"

    @classmethod
    def from_env(cls) -> "AgentConfig":
        return cls(
            livekit_url=os.getenv("LIVEKIT_URL"),
            livekit_api_key=os.getenv("LIVEKIT_API_KEY"),
            livekit_api_secret=os.getenv("LIVEKIT_API_SECRET"),
            room_name=os.getenv("LIVEKIT_ROOM_NAME", "claude-voice"),
            deepgram_api_key=os.getenv("DEEPGRAM_API_KEY"),
            google_api_key=os.getenv("GOOGLE_API_KEY"),
            cartesia_api_key=os.getenv("CARTESIA_API_KEY"),
            bridge_url=os.getenv("BRIDGE_SERVER_URL", "http://localhost:3001"),
            voice_id=os.getenv("VOICE_ID", "79a125e8-cd45-4c81-8325-6caccb55b5a8")
        )


class VoiceAssistant(agents.Agent):
    """Voice agent that bridges LiveKit to Claude Code"""

    def __init__(self, config: AgentConfig):
        super().__init__(
            stt=deepgram.STT(api_key=config.deepgram_api_key),
            llm=google.LLM(api_key=config.google_api_key, model="gemini-2.0-flash-exp"),
            tts=cartesia.TTS(api_key=config.cartesia_api_key, voice_id=config.voice_id)
        )

        self.config = config
        self.claude = ClaudeBridge(config.bridge_url)
        self.session_started = False

    async def on_enter(self):
        """Called when participant joins"""
        await self.say("Hello! I'm ready to help you control Claude Code with your voice.")

    async def on_user_message(self, message: agents.UserMessage):
        """Called when user sends a message (via voice or text)"""

        # Classify intent
        intent = await self._classify_intent(message.content)

        if intent == "SEND_TO_CLAUDE":
            await self._send_to_claude(message.content)
        elif intent == "CHECK_STATUS":
            await self._check_status()
        elif intent == "INTERRUPT":
            await self._interrupt()
        else:
            # Treat as general message to Claude
            await self._send_to_claude(message.content)

    async def _classify_intent(self, text: str) -> str:
        """Classify user intent using LLM"""

        prompt = f"""Classify this request: "{text}"

Return ONLY one of these exact values:
- SEND_TO_CLAUDE - Send this as a prompt to Claude Code
- CHECK_STATUS - Check Claude Code session status
- INTERRUPT - Stop current Claude Code action

Your response:"""

        response = await self.llm.chat([
            {"role": "user", "content": prompt}
        ])

        result = response.content.strip().upper()

        # Default to SEND_TO_CLAUDE if unclear
        if "SEND_TO_CLAUDE" in result:
            return "SEND_TO_CLAUDE"
        elif "CHECK_STATUS" in result:
            return "CHECK_STATUS"
        elif "INTERRUPT" in result:
            return "INTERRUPT"
        else:
            return "SEND_TO_CLAUDE"

    async def _send_to_claude(self, message: str):
        """Send message to Claude Code and speak the response"""

        await self.say("Sending to Claude Code...")

        try:
            result = await self.claude.send_prompt(message)

            # Summarize for voice
            summary = await self._summarize_for_voice(result)
            await self.say(summary)

        except Exception as e:
            await self.say(f"Sorry, there was an error: {str(e)}")

    async def _check_status(self):
        """Check and speak Claude Code status"""

        try:
            status = await self.claude.get_status()

            if not status.get("connected"):
                await self.say("Claude Code is not connected.")
                return

            session_id = status.get("sessionId", "unknown")
            current_status = status.get("status", "unknown")
            pending = status.get("pendingPermission")

            response = f"Claude Code is connected. Session {session_id[-8:]}. "
            response += f"Status: {current_status}."

            if pending:
                response += f" There's a pending permission request for {pending['tool_name']}."

            await self.say(response)

        except Exception as e:
            await self.say(f"Error checking status: {str(e)}")

    async def _interrupt(self):
        """Interrupt current Claude Code action"""

        try:
            await self.claude.interrupt()
            await self.say("Interrupted Claude Code.")
        except Exception as e:
            await self.say(f"Error interrupting: {str(e)}")

    async def _summarize_for_voice(self, result: dict) -> str:
        """Summarize Claude's response for voice output"""

        if result.get("is_error"):
            return f"Claude encountered an error: {result.get('errors', ['Unknown error'])[0]}"

        message_text = result.get("result", "")
        cost = result.get("total_cost_usd", 0)
        turns = result.get("num_turns", 0)

        # Use LLM to summarize
        prompt = f"""Summarize this Claude Code response for voice output.

Original response:
{message_text[:1000]}

Guidelines:
- Keep it under 50 words
- Focus on what was accomplished
- Mention any files created/modified
- Speak naturally

Your summary:"""

        response = await self.llm.chat([
            {"role": "user", "content": prompt}
        ])

        summary = response.content.strip()

        # Add cost info if significant
        if cost > 0.01:
            summary += f" Cost: ${cost:.4f}."

        return summary


async def entrypoint(ctx: agents.JobContext):
    """LiveKit agent entrypoint"""

    config = AgentConfig.from_env()
    agent = VoiceAssistant(config)

    # Start the agent
    await agent.start(ctx.room)


if __name__ == "__main__":
    import logging

    logging.basicConfig(level=logging.INFO)

    config = AgentConfig.from_env()

    # Run using LiveKit CLI
    agents.run_app(
        WorkerOptions(
            entrypoint_fnc=entrypoint,
            api_key=config.livekit_api_key,
            api_secret=config.livekit_api_secret,
            websocket_url=config.livekit_url
        )
    )
