### 3.2 Claude Bridge (HTTP Client)

**File:** `agent/claude_bridge.py`

```python
import asyncio
import httpx
from typing import Optional, Dict, Any


class ClaudeBridge:
    """HTTP client to communicate with the WebSocket server"""

    def __init__(self, base_url: str):
        self.base_url = base_url.rstrip("/")
        self.client = httpx.AsyncClient(timeout=60.0)

    async def close(self):
        await self.client.aclose()

    async def send_prompt(self, message: str) -> Dict[str, Any]:
        """Send a user message to Claude Code"""

        response = await self.client.post(
            f"{self.base_url}/api/send",
            json={"message": message}
        )
        response.raise_for_status()
        return response.json()

    async def get_status(self) -> Dict[str, Any]:
        """Get current session status"""

        response = await self.client.get(f"{self.base_url}/api/status")
        response.raise_for_status()
        return response.json()

    async def respond_to_permission(
        self,
        request_id: str,
        decision: str  # "allow" or "deny"
    ) -> Dict[str, Any]:
        """Respond to a permission request"""

        response = await self.client.post(
            f"{self.base_url}/api/permission",
            json={"request_id": request_id, "decision": decision}
        )
        response.raise_for_status()
        return response.json()

    async def interrupt(self) -> Dict[str, Any]:
        """Interrupt current Claude Code action"""

        response = await self.client.post(f"{self.base_url}/api/interrupt")
        response.raise_for_status()
        return response.json()

    async def get_history(self) -> Dict[str, Any]:
        """Get message history"""

        response = await self.client.get(f"{self.base_url}/api/history")
        response.raise_for_status()
        return response.json()

    async def subscribe_events(self, callback):
        """Subscribe to SSE events for real-time updates"""

        async with self.client.stream("GET", f"{self.base_url}/api/events") as response:
            async for line in response.aiter_lines():
                if line.startswith("data: "):
                    data = line[6:]  # Remove "data: " prefix
                    import json
                    try:
                        event = json.loads(data)
                        await callback(event)
                    except json.JSONDecodeError:
                        pass
