```javascript
// State
const state = {
  connected: false,
  sessionId: null,
  transcript: '',
  response: '',
  toolCalls: [],
  pendingPermission: null,
  stats: {
    turns: 0,
    tokens: 0,
    cost: 0,
    tools: 0
  }
}

// DOM Elements
const elements = {
  connectionStatus: document.getElementById('connection-status'),
  sessionId: document.getElementById('session-id'),
  transcript: document.getElementById('transcript'),
  response: document.getElementById('response'),
  toolCalls: document.getElementById('tool-calls'),
  permissionArea: document.getElementById('permission-area'),
  btnInterrupt: document.getElementById('btn-interrupt'),
  statTurns: document.getElementById('stat-turns'),
  statTokens: document.getElementById('stat-tokens'),
  statCost: document.getElementById('stat-cost'),
  statTools: document.getElementById('stat-tools')
}

// SSE Connection
function connectSSE() {
  const eventSource = new EventSource('http://localhost:3001/api/events')

  eventSource.addEventListener('connect', (e) => {
    console.log('SSE connected')
  })

  eventSource.addEventListener('message', (e) => {
    try {
      const event = JSON.parse(e.data)
      handleEvent(event)
    } catch (err) {
      console.error('Failed to parse event:', err)
    }
  })

  eventSource.onerror = (err) => {
    console.error('SSE error:', err)
  }

  return eventSource
}

// Event Handlers
function handleEvent(event) {
  console.log('Event:', event.type, event.data)

  switch (event.type) {
    case 'connected':
      handleConnected(event.data)
      break
    case 'disconnected':
      handleDisconnected(event.data)
      break
    case 'assistant':
      handleAssistant(event.data)
      break
    case 'stream_event':
      handleStreamEvent(event.data)
      break
    case 'result':
      handleResult(event.data)
      break
    case 'permission_request':
      handlePermissionRequest(event.data)
      break
    case 'tool_progress':
      handleToolProgress(event.data)
      break
    case 'permission_response':
      handlePermissionResponse(event.data)
      break
  }
}

function handleConnected(data) {
  state.connected = true
  state.sessionId = data.sessionId
  updateConnectionStatus('connected')
  elements.sessionId.textContent = data.sessionId?.slice(-8) || 'Unknown'
}

function handleDisconnected(data) {
  state.connected = false
  updateConnectionStatus('disconnected')
}

function handleAssistant(data) {
  if (data.text) {
    state.response = data.text
    elements.response.textContent = data.text
  }
}

function handleStreamEvent(data) {
  // Streaming delta update
  if (data.delta) {
    elements.response.textContent = (state.response + data.text).trim()
    state.response = elements.response.textContent
  }
}

function handleResult(data) {
  state.stats.turns = data.num_turns || 0
  state.stats.tokens = data.usage?.input_tokens + data.usage?.output_tokens || 0
  state.stats.cost = data.total_cost_usd || 0
  updateStats()

  if (data.is_error) {
    elements.response.textContent += '\n\n[ERROR]: ' + (data.errors?.join('\n') || 'Unknown error')
  }
}

function handlePermissionRequest(data) {
  state.pendingPermission = data
  renderPermissionRequest()
}

function handlePermissionResponse(data) {
  if (state.pendingPermission?.request_id === data.request_id) {
    state.pendingPermission = null
    renderPermissionRequest()
  }
}

function handleToolProgress(data) {
  const existing = state.toolCalls.find(t => t.toolUseId === data.tool_use_id)
  if (existing) {
    existing.status = 'executing'
    existing.elapsed = data.elapsed_time_seconds
  } else {
    state.toolCalls.push({
      toolUseId: data.tool_use_id,
      toolName: data.tool_name,
      status: 'executing',
      elapsed: data.elapsed_time_seconds
    })
  }
  renderToolCalls()
}

// UI Updates
function updateConnectionStatus(status) {
  elements.connectionStatus.className = `status-badge ${status}`
  elements.connectionStatus.textContent = status.charAt(0).toUpperCase() + status.slice(1)
}

function updateStats() {
  elements.statTurns.textContent = state.stats.turns
  elements.statTokens.textContent = state.stats.tokens.toLocaleString()
  elements.statCost.textContent = '$' + state.stats.cost.toFixed(4)
  elements.statTools.textContent = state.toolCalls.length
}

function renderToolCalls() {
  if (state.toolCalls.length === 0) {
    elements.toolCalls.innerHTML = '<div style="color: #888; text-align: center; padding: 20px;">No tool calls yet</div>'
    return
  }

  elements.toolCalls.innerHTML = state.toolCalls.map(tool => `
    <div class="tool-call ${tool.status}">
      <span class="tool-name">${tool.toolName}</span>
      <span class="tool-input">${JSON.stringify(tool.input || {})}</span>
      <span class="tool-status">${tool.status}</span>
    </div>
  `).join('')
}

function renderPermissionRequest() {
  if (!state.pendingPermission) {
    elements.permissionArea.innerHTML = '<div style="color: #888; text-align: center; padding: 20px;">No pending permissions</div>'
    return
  }

  const req = state.pendingPermission
  elements.permissionArea.innerHTML = `
    <div class="permission-request">
      <strong>Tool:</strong> ${req.tool_name}<br>
      <strong>Input:</strong> <code>${JSON.stringify(req.input)}</code>
      <div class="permission-actions">
        <button class="btn btn-allow" onclick="respondPermission(true)">Allow</button>
        <button class="btn btn-deny" onclick="respondPermission(false)">Deny</button>
      </div>
    </div>
  `
}

// Actions
async function respondPermission(allow) {
  if (!state.pendingPermission) return

  try {
    const response = await fetch('http://localhost:3001/api/permission', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        request_id: state.pendingPermission.request_id,
        decision: allow ? 'allow' : 'deny'
      })
    })
    await response.json()
  } catch (err) {
    console.error('Failed to respond to permission:', err)
  }
}

async function interrupt() {
  try {
    await fetch('http://localhost:3001/api/interrupt', { method: 'POST' })
  } catch (err) {
    console.error('Failed to interrupt:', err)
  }
}

// Initialize
elements.btnInterrupt.addEventListener('click', interrupt)

// Initial connection check
fetch('http://localhost:3001/api/status')
  .then(r => r.json())
  .then(status => {
    if (status.connected) {
      handleConnected({ sessionId: status.sessionId })
    }
  })
  .catch(console.error)

// Start SSE
connectSSE()
