async def test_full_flow():
    """Test the complete voice-to-claude flow"""

    # 1. Connect to WebSocket server
    ws = await websockets.connect('ws://localhost:8765')

    # 2. Wait for system/init
    init_msg = json.loads(await ws.recv())
    assert init_msg['type'] == 'system'
    assert init_msg['subtype'] == 'init'
    session_id = init_msg['session_id']

    # 3. Send user message
    user_msg = {
        'type': 'user',
        'message': {'role': 'user', 'content': 'Say hello'},
        'parent_tool_use_id': None,
        'session_id': session_id
    }
    await ws.send(json.dumps(user_msg) + '\n')

    # 4. Receive messages until result
    messages = []
    async for message in ws:
        data = json.loads(message)
        messages.append(data)
        if data.get('type') == 'result':
            break

    # 5. Verify flow
    assert any(m.get('type') == 'assistant' for m in messages)
    assert messages[-1]['type'] == 'result'

    print("Integration test passed!")

if __name__ == '__main__':
    asyncio.run(test_full_flow())
